Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world"),
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFoundResponse_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.NotFound,
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new FakeHttpHandler(new HttpResponseMessage(HttpStatusCode.OK));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_TimeoutViaToken_ThrowsOperationCanceled()
    {
        // Arrange — handler delays longer than the token allows
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        var handler = new FakeHttpHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(10), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler to avoid external mocking libraries
    private sealed class FakeHttpHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public FakeHttpHandler(HttpResponseMessage response)
            : this((_, _) => Task.FromResult(response)) { }

        public FakeHttpHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | How |
|---------|-----|
| Sealed class | `public sealed class` for perf/clarity |
| Constructor-injected TestContext | Enables `_testContext.CancellationToken` |
| `[Timeout]` + CancellationToken | Test auto-cancels if it hangs — pass `_testContext.CancellationToken` into your async code |
| Pre-cancelled token | Tests immediate cancellation path |
| Short-lived token | Tests timeout mid-operation |
| `Assert.ThrowsExactlyAsync` | Modern exception assertion (not `[ExpectedException]`) |

The `[Timeout]` attribute signals the runner to cancel `TestContext.CancellationToken` after the specified milliseconds, so always pass that token through to your async calls. For cancellation-specific tests, create your own `CancellationTokenSource` to control timing precisely.
